import React from 'react';
import Article from '../Article.js';
import './Head.css';
import { stories } from '../Stories.js';

var temp = stories;

function Head() {
  return (
    <div className='Head'>

      <Article index={76}/>
      <div id='description'>
        <p>Dozens of activists gathered at the Jackie Robinson Stadium parking lot Sunday to criticize UCLA’s role in letting the LAPD
          use the lot to detain protesters in June and to protest campus policing. Attendees heard from speakers including Melina Abdullah,
          a co-founder of Black Lives Matter Los Angeles, Naomi Riley, the Undergraduate Students Association Council president, and Jodi Scofield,
          a graduate student who said she was detained on the lot in June. Read more <a href='https://dailybruin.com/2020/11/01/activists-gather-at-jackie-robinson-stadium-to-protest-ucpd-lapd'> here &#10063;</a></p>
      </div>

    </div>
  );
}

export default Head;
